                descSpan.textContent = optText || '（空选项）';

                btn.appendChild(tagSpan);
                btn.appendChild(descSpan);

                btn.addEventListener('click', function(e) {
                    e.stopPropagation();
                    const text = descSpan.textContent.trim();
                    if (text === '（空选项）' || text === '') {
                        showToast('❌ 无内容');
                        return;
                    }
                    copyText(text);
                });

                container.appendChild(btn);
            });
        })();
