        <span id="raw-fest">$7</span><span id="raw-clue">$8</span><span id="raw-goal">$9</span>
    </div>

    <script>
        function getRaw(id) { const el = document.getElementById(id); return el ? el.innerText.trim() : ''; }
        let data = window.omateLivePageData || {};

        if(Object.keys(data).length === 0) {
            data = {
                time: getRaw('raw-time'), location: getRaw('raw-loc'), weather: getRaw('raw-wea'),
                character: { outfit: getRaw('raw-fit'), affection: parseInt(getRaw('raw-love')) || 0 },
                festival: getRaw('raw-fest') && getRaw('raw-fest') !== '无' ? { name: getRaw('raw-fest'), date: '', desc: '' } : null,
