                clues: getRaw('raw-clue') ? getRaw('raw-clue').split('\n').filter(l => l.trim() !== '') : []
            };
            const moodRaw = getRaw('raw-mood');
            if(moodRaw) {
                const moodMatch = moodRaw.match(/^(\p{Emoji}+)?\s*(.*)$/u);
                data.character.moodIcon = moodMatch?.[1] || '😐';
                data.character.mood = moodMatch?.[2] || moodRaw;
            }
        }

        function initParticles() {
            const container = document.getElementById('particles-container');
            for(let i=0; i<6; i++) createPetal(container, Math.random() * 5000);
