            if(bubbleInterval) return;
            const container = document.getElementById('love-bubbles-container');
            bubbleInterval = setInterval(() => {
                if(document.visibilityState === 'hidden') return;
                const bubble = document.createElement('div');
                bubble.className = 'love-bubble';
                const size = 12 + Math.random() * 10; 
                bubble.style.fontSize = size + 'px'; bubble.innerText = Math.random() > 0.6 ? '💗' : '🌸';
                bubble.style.left = (20 + Math.random() * 60) + '%'; bubble.style.animationDuration = (3 + Math.random() * 2) + 's';
                container.appendChild(bubble);
                bubble.addEventListener('animationend', () => bubble.remove());
            }, 1200);
        }

        function triggerMoodAnim(el) {
            const emojis = ['✨', '💖', '🌸', '🦋'];
            for(let i=0; i<6; i++) {
                const span = document.createElement('span'); span.className = 'pop-emoji';
                span.innerText = emojis[Math.floor(Math.random() * emojis.length)];
