                span.style.setProperty('--ex', Math.cos(angle) * dist + 'px'); span.style.setProperty('--ey', Math.sin(angle) * dist + 'px');
                el.appendChild(span); setTimeout(() => span.remove(), 800);
            }
        }

        function triggerWeatherAnim(el) { el.style.transform = 'scale(0.9)'; setTimeout(() => el.style.transform = 'scale(1)', 150); }

        function render() {
            if (data.time) {
                const parts = data.time.split(' ');
                const timeStr = parts.find(p => p.includes(':')) || data.time;
                let dateStr = parts[0] || '';
                const dateMatch = dateStr.match(/(\d{1,2})月(\d{1,2})日/) || dateStr.match(/(\d{1,2})\/(\d{1,2})/);
                if (dateMatch) dateStr = `${dateMatch[1]}/${dateMatch[2]}`; else dateStr = dateStr.slice(5) || dateStr;
                const weekStr = parts.find(p => /Mon|Tue|Wed|Thu|Fri|Sat|Sun|星期|周/.test(p)) || '';
                document.getElementById('time-hhmm').innerText = timeStr;
                document.getElementById('full-date').innerText = dateStr + (weekStr ? ` ${weekStr}` : '');
            }

            if (data.weather) {
                const match = data.weather.match(/(\p{Emoji}+)/u);
                if (match) {
                    document.getElementById('weather-icon-span').innerText = match[0];
                    document.getElementById('weather-text-span').innerText = data.weather.replace(match[0], '').trim();
                } else {
                    document.getElementById('weather-icon-span').innerText = '🌤';
                    document.getElementById('weather-text-span').innerText = data.weather;
                }
            }

            if (data.character && data.character.mood) {
                document.getElementById('char-section').style.display = 'block';
                const c = data.character;
                document.getElementById('mood-icon').innerText = c.moodIcon || '😐';
                document.getElementById('mood-text').innerText = c.mood || '...';
                document.getElementById('outfit-text').innerText = c.outfit || '常规便服';

                const love = Math.min(Math.max(c.affection || 0, 0), 100);
                document.getElementById('love-value').innerText = `${love}%`;
                const fillEl = document.getElementById('love-fill');

                let gradient = '', textColor = '';
                if (love < 30) { gradient = 'linear-gradient(90deg, #95d495, #b8e6b8)'; textColor = '#5ea35e'; }
                else if (love < 60) { gradient = 'linear-gradient(90deg, #fce38a, #ffb7b9)'; textColor = '#e08e79'; }
                else { gradient = 'linear-gradient(90deg, #ff9a9e, #ffc3a0)'; textColor = '#ff6b6b'; }

                if (love > 0) startBubbles();

                setTimeout(() => {
                    fillEl.style.width = `${love}%`; fillEl.style.backgroundImage = gradient;
                    document.getElementById('love-value').style.color = textColor;
                }, 100);
            }

            if (data.location) document.getElementById('location-text').innerText = data.location;
            const festDescEl = document.getElementById('fest-desc');
            if (data.festival && data.festival.name && data.festival.name !== '无') {
                document.getElementById('fest-box').style.display = 'flex';
                document.getElementById('fest-text').innerText = `(${data.festival.date || ''} ${data.festival.name})`;
                if (data.festival.desc) { festDescEl.innerText = data.festival.desc; festDescEl.style.display = 'block'; }
            }

            const goalsList = document.getElementById('goals-list');
            goalsList.innerHTML = '';
            if (data.goals && data.goals.length > 0) {
                data.goals.forEach(goalStr => {
                    const isCompleted = goalStr.includes('-[x]') || goalStr.includes('[x]') || goalStr.includes('已完成');
                    let prefix = 'TASK', cssClass = 'tag-default', content = goalStr.replace('-[x]', '').replace('[x]', '').trim();
                    if (content.includes('{{user}}')) { prefix = 'ME'; cssClass = 'tag-user'; content = content.replace('{{user}}', '').trim(); }
                    else if (content.includes('{{char}}')) { prefix = 'CHAR'; cssClass = 'tag-char'; content = content.replace('{{char}}', '').trim(); }
                    else if (content.includes('[共同]')) { prefix = 'BOTH'; cssClass = 'tag-both'; content = content.replace('[共同]', '').trim(); }

                    const div = document.createElement('div');
                    div.className = `goal-item ${isCompleted ? 'completed' : ''}`;
                    div.innerHTML = `<div class="goal-tag ${cssClass}">${prefix}</div><div class="goal-text">${content}</div>${isCompleted ? '<div class="stamp-flower"></div>' : ''}`;
                    goalsList.appendChild(div);
                });
            } else { goalsList.innerHTML = '<div class="empty-hint">暂无行动目标</div>'; }

            const cluesList = document.getElementById('clues-list');
            cluesList.innerHTML = '';
            if (data.clues && data.clues.length > 0) {
                data.clues.forEach(clueStr => {
                    const isCompleted = clueStr.includes('-[x]') || clueStr.includes('[x]');
                    const content = clueStr.replace('-[x]', '').replace('[x]', '').trim();
                    const div = document.createElement('div');
                    div.className = `clue-item ${isCompleted ? 'completed' : ''}`;
                    div.innerHTML = `${content}<span class="clue-solved-mark">真相大白</span>`;
                    cluesList.appendChild(div);
                });
            } else { cluesList.innerHTML = '<div class="empty-hint">未发现伏笔信息</div>'; }
        }

        initParticles();
        render();
    </script>
</body>
</html>
